// This service handles SQLite via sql.js in the browser
// It persists the binary database to localStorage to simulate a persistent server DB

let db: any = null;
const DB_STORAGE_KEY = 'alara_sqlite_db_bin';

export const initDB = async () => {
  if (db) return db;

  try {
    // @ts-ignore - sql.js is loaded via script tag
    const SQL = await window.initSqlJs({
      locateFile: (file: string) => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.8.0/${file}`
    });

    const savedDb = localStorage.getItem(DB_STORAGE_KEY);

    if (savedDb) {
      const uInt8Array = new Uint8Array(JSON.parse(savedDb));
      db = new SQL.Database(uInt8Array);
    } else {
      db = new SQL.Database();
      initTables();
    }

    console.log("SQLite Database Initialized");
    return db;
  } catch (err) {
    console.error("Failed to init SQLite:", err);
    return null;
  }
};

const initTables = () => {
  if (!db) return;

  // Create Users Table
  db.run(`
    CREATE TABLE IF NOT EXISTS users (
      id TEXT PRIMARY KEY,
      username TEXT UNIQUE,
      name TEXT,
      password TEXT,
      role TEXT,
      phone TEXT,
      created_at TEXT
    );
  `);

  // Create Submissions Table
  db.run(`
    CREATE TABLE IF NOT EXISTS submissions (
      id TEXT PRIMARY KEY,
      user_id TEXT,
      date TEXT,
      student_name TEXT,
      email TEXT,
      phone TEXT,
      school_name TEXT,
      address TEXT,
      academic_strengths TEXT,
      interests TEXT,
      soft_skills TEXT,
      work_preference TEXT,
      env_preference TEXT,
      top_major TEXT,
      match_score INTEGER
    );
  `);

  saveDB();
};

export const saveDB = () => {
  if (!db) return;
  const data = db.export();
  const arr = Array.from(data);
  localStorage.setItem(DB_STORAGE_KEY, JSON.stringify(arr));
};

export const getDB = () => db;

// SQL Helper to run query and return objects
export const runQuery = (sql: string, params: any[] = []) => {
  if (!db) return [];
  const stmt = db.prepare(sql);
  stmt.bind(params);
  const result = [];
  while (stmt.step()) {
    result.push(stmt.getAsObject());
  }
  stmt.free();
  return result;
};

export const executeRun = (sql: string, params: any[] = []) => {
  if (!db) return;
  db.run(sql, params);
  saveDB();
};

import { UserProfile, MajorRecommendation } from '../types';
import { executeRun, runQuery } from './db';

// Fallback logic handled within db.ts (persisting SQLite binary to localstorage)

export interface Submission {
  id: string;
  date: string;
  profile: UserProfile;
  topMajor: string;
  matchScore: number;
}

export const saveSubmission = (profile: UserProfile, recommendations: MajorRecommendation[]) => {
  try {
    const id = Date.now().toString();
    const date = new Date().toISOString();
    const topMajor = recommendations[0]?.title || 'غير محدد';
    const matchScore = recommendations[0]?.matchScore || 0;

    // Use SQLite Insert
    executeRun(`
      INSERT INTO submissions (
        id, user_id, date, student_name, email, phone, school_name, address,
        academic_strengths, interests, soft_skills, work_preference, env_preference,
        top_major, match_score
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `, [
      id,
      profile.userId || null,
      date,
      profile.name,
      profile.email,
      profile.phone,
      profile.schoolName,
      profile.address,
      JSON.stringify(profile.academicStrengths),
      JSON.stringify(profile.interests),
      JSON.stringify(profile.softSkills),
      profile.workPreference,
      profile.environmentPreference,
      topMajor,
      matchScore
    ]);

    console.log('Submission saved successfully to SQLite');
  } catch (error) {
    console.error('Failed to save submission:', error);
  }
};

export const getSubmissions = (): Submission[] => {
  try {
    const rows = runQuery(`SELECT * FROM submissions ORDER BY date DESC`);

    return rows.map((row: any) => ({
      id: row.id,
      date: row.date,
      topMajor: row.top_major,
      matchScore: row.match_score,
      profile: {
        userId: row.user_id,
        name: row.student_name,
        email: row.email,
        phone: row.phone,
        schoolName: row.school_name,
        address: row.address,
        academicStrengths: JSON.parse(row.academic_strengths || '[]'),
        interests: JSON.parse(row.interests || '[]'),
        softSkills: JSON.parse(row.soft_skills || '[]'),
        workPreference: row.work_preference,
        environmentPreference: row.env_preference
      }
    }));
  } catch (error) {
    console.error('Failed to load submissions:', error);
    return [];
  }
};

export const clearSubmissions = () => {
  executeRun(`DELETE FROM submissions`);
};

